37	type PopoverMenuItem = MenuItemProps & {
38	    /** Text label */
39	    text: string;
40	
41	    /** A callback triggered when this item is selected */
42	    onSelected?: () => void;
43	
44	    /** Sub menu items to be rendered after a menu item is selected */
45	    subMenuItems?: PopoverMenuItem[];
46	
47	    /** Back button text to be shown if sub menu items are opened */
48	    backButtonText?: string;
49	
50	    /** Determines whether the menu item is disabled or not */
51	    disabled?: boolean;
52	
53	    /** Determines whether the menu item's onSelected() function is called after the modal is hidden
54	     *  It is meant to be used in situations where, after clicking on the modal, another one is opened.
55	     */
56	    shouldCallAfterModalHide?: boolean;
57	
58	    /** Whether to close all modals */
59	    shouldCloseAllModals?: boolean;
60	
61	    pendingAction?: PendingAction;
62	
63	    rightIcon?: React.FC<SvgProps>;
64	
65	    key?: string;
66	
67	    /** Whether to keep the modal open after clicking on the menu item */
68	    shouldKeepModalOpen?: boolean;
69	
70	    /** Test identifier used to find elements in unit and e2e tests */
71	    testID?: string;
72	
73	    /** Whether to show a loading spinner icon for the menu item */
74	    shouldShowLoadingSpinnerIcon?: boolean;
75	
76	    /** Whether to close the modal on select */
77	    shouldCloseModalOnSelect?: boolean;
78	};
79	
80	type PopoverModalProps = Pick<ModalProps, 'animationIn' | 'animationOut' | 'animationInTiming' | 'animationOutTiming'> & Pick<ReanimatedModalProps, 'animationInDelay'>;
81	
82	type PopoverMenuProps = Partial<PopoverModalProps> & {
83	    /** Callback method fired when the user requests to close the modal */
84	    onClose: () => void;
85	
86	    /** Optional callback passed to popover's children container */
87	    onLayout?: (e: LayoutChangeEvent) => void;
88	
89	    /** Callback method fired when the modal is shown */
90	    onModalShow?: () => void;
91	
92	    /** Callback method fired when the modal is hidden */
93	    onModalHide?: () => void;
94	
95	    /** State that determines whether to display the modal or not */
96	    isVisible: boolean;
97	
98	    /** Callback to fire when a CreateMenu item is selected */
99	    onItemSelected?: (selectedItem: PopoverMenuItem, index: number, event?: GestureResponderEvent | KeyboardEvent) => void;
100	
101	    /** Menu items to be rendered on the list */
102	    menuItems: PopoverMenuItem[];
103	
104	    /** Optional non-interactive text to display as a header for any create menu */
105	    headerText?: string;
106	
107	    /** Whether disable the animations */
108	    disableAnimation?: boolean;
109	
110	    /** The horizontal and vertical anchors points for the popover */
111	    anchorPosition: AnchorPosition;
112	
113	    /** Ref of the anchor */
114	    anchorRef: RefObject<View | HTMLDivElement | null>;
115	
116	    /** Where the popover should be positioned relative to the anchor points. */
117	    anchorAlignment?: AnchorAlignment;
118	
119	    /** Whether we don't want to show overlay */
120	    withoutOverlay?: boolean;
121	
122	    /** Should we announce the Modal visibility changes? */
123	    shouldSetModalVisibility?: boolean;
124	
125	    /** Whether we want to show the popover on the right side of the screen */
126	    fromSidebarMediumScreen?: boolean;
127	
128	    /**
129	     * Whether the modal should enable the new focus manager.
130	     * We are attempting to migrate to a new refocus manager, adding this property for gradual migration.
131	     * */
132	    shouldEnableNewFocusManagement?: boolean;
133	
134	    /** How to re-focus after the modal is dismissed */
135	    restoreFocusType?: BaseModalProps['restoreFocusType'];
136	
137	    /** Whether to show the selected option checkmark */
138	    shouldShowSelectedItemCheck?: boolean;
139	
140	    /** The style of content container which wraps all child views */
141	    containerStyles?: StyleProp<ViewStyle>;
142	
143	    /** Used to apply styles specifically to the header text */
144	    headerStyles?: StyleProp<TextStyle>;
145	
146	    /** Modal container styles  */
147	    innerContainerStyle?: ViewStyle;
148	
149	    /** These styles will be applied to the scroll view content container which wraps all of the child views */
150	    scrollContainerStyle?: StyleProp<ViewStyle>;
151	
152	    /** Whether we should wrap the list item in a scroll view */
153	    shouldUseScrollView?: boolean;
154	
155	    /** Whether we should set a max height to the popover content */
156	    shouldEnableMaxHeight?: boolean;
157	
158	    /** Whether to update the focused index on a row select */
159	    shouldUpdateFocusedIndex?: boolean;
160	
161	    /** Should we apply padding style in modal itself. If this value is false, we will handle it in ScreenWrapper */
162	    shouldUseModalPaddingStyle?: boolean;
163	
164	    /** Whether we want to avoid the safari exception of ignoring shouldCallAfterModalHide  */
165	    shouldAvoidSafariException?: boolean;
166	
167	    /** Used to locate the component in the tests */
168	    testID?: string;
169	};
170	
171	const renderWithConditionalWrapper = (shouldUseScrollView: boolean, contentContainerStyle: StyleProp<ViewStyle>, children: ReactNode): React.JSX.Element => {
172	    if (shouldUseScrollView) {
173	        return <ScrollView contentContainerStyle={contentContainerStyle}>{children}</ScrollView>;
174	    }
175	    // eslint-disable-next-line react/jsx-no-useless-fragment
176	    return <>{children}</>;
177	};
178	
179	function getSelectedItemIndex(menuItems: PopoverMenuItem[]) {
180	    return menuItems.findIndex((option) => option.isSelected);
181	}
182	
183	function PopoverMenu(props: PopoverMenuProps) {
184	    const wasVisible = usePrevious(props.isVisible);
185	    // Do not render the PopoverMenu before it gets opened. Until then both values are false
186	    if (!wasVisible && !props.isVisible) {
187	        return null;
188	    }
189	    return <BasePopoverMenu {...props} />;
190	}
191	
192	function BasePopoverMenu({
193	    menuItems,
194	    onItemSelected,
195	    isVisible,
196	    anchorPosition,
197	    anchorRef,
198	    onClose,
199	    onLayout,
200	    onModalShow,
201	    onModalHide,
202	    headerText,
203	    fromSidebarMediumScreen,
204	    anchorAlignment = {
205	        horizontal: CONST.MODAL.ANCHOR_ORIGIN_HORIZONTAL.LEFT,
206	        vertical: CONST.MODAL.ANCHOR_ORIGIN_VERTICAL.BOTTOM,
207	    },
208	    animationIn = 'fadeIn',
209	    animationInDelay,
210	    animationOut = 'fadeOut',
211	    animationInTiming = CONST.ANIMATED_TRANSITION,
212	    animationOutTiming,
213	    disableAnimation = true,
214	    withoutOverlay = false,
215	    shouldSetModalVisibility = true,
216	    shouldEnableNewFocusManagement,
217	    restoreFocusType,
218	    shouldShowSelectedItemCheck = false,
219	    containerStyles,
220	    headerStyles,
221	    innerContainerStyle,
222	    scrollContainerStyle,
223	    shouldUseScrollView = false,
224	    shouldEnableMaxHeight = true,
225	    shouldUpdateFocusedIndex = true,
226	    shouldUseModalPaddingStyle,
227	    shouldAvoidSafariException = false,
228	    testID,
229	}: PopoverMenuProps) {
230	    const styles = useThemeStyles();
231	    const theme = useTheme();
232	    const StyleUtils = useStyleUtils();
233	    // We need to use isSmallScreenWidth instead of shouldUseNarrowLayout to apply correct popover styles
234	    // eslint-disable-next-line rulesdir/prefer-shouldUseNarrowLayout-instead-of-isSmallScreenWidth
235	    const {isSmallScreenWidth} = useResponsiveLayout();
236	    const [currentMenuItems, setCurrentMenuItems] = useState(menuItems);
237	    const currentMenuItemsFocusedIndex = getSelectedItemIndex(currentMenuItems);
238	    const [enteredSubMenuIndexes, setEnteredSubMenuIndexes] = useState<readonly number[]>(CONST.EMPTY_ARRAY);
239	    const {windowHeight} = useWindowDimensions();
240	    const platform = getPlatform();
241	    const isWebOrDesktop = platform === CONST.PLATFORM.WEB || platform === CONST.PLATFORM.DESKTOP;
242	    const [focusedIndex, setFocusedIndex] = useArrowKeyFocusManager({initialFocusedIndex: currentMenuItemsFocusedIndex, maxIndex: currentMenuItems.length - 1, isActive: isVisible});
243	
244	    const selectItem = (index: number, event?: GestureResponderEvent | KeyboardEvent) => {
245	        const selectedItem = currentMenuItems.at(index);
246	        if (!selectedItem) {
247	            return;
248	        }
249	        if (selectedItem?.subMenuItems) {
250	            setCurrentMenuItems([...selectedItem.subMenuItems]);
251	            setEnteredSubMenuIndexes([...enteredSubMenuIndexes, index]);
252	            const selectedSubMenuItemIndex = selectedItem?.subMenuItems.findIndex((option) => option.isSelected);
253	            setFocusedIndex(selectedSubMenuItemIndex);
254	        } else if (selectedItem.shouldCallAfterModalHide && (!isSafari() || shouldAvoidSafariException)) {
255	            onItemSelected?.(selectedItem, index, event);
256	            if (selectedItem.shouldCloseModalOnSelect !== false) {
257	                close(
258	                    () => {
259	                        selectedItem.onSelected?.();
260	                    },
261	                    undefined,
262	                    selectedItem.shouldCloseAllModals,
263	                );
264	            } else {
265	                selectedItem.onSelected?.();
266	            }
267	        } else {
268	            onItemSelected?.(selectedItem, index, event);
269	            selectedItem.onSelected?.();
270	        }
271	    };
272	
273	    const getPreviousSubMenu = () => {
274	        let currentItems = menuItems;
275	        for (let i = 0; i < enteredSubMenuIndexes.length - 1; i++) {
276	            const nextItems = currentItems[enteredSubMenuIndexes[i]].subMenuItems;
277	            if (!nextItems) {
278	                return currentItems;
279	            }
280	            currentItems = nextItems;
281	        }
282	        return currentItems;
283	    };
284	
285	    const renderBackButtonItem = () => {
286	        const previousMenuItems = getPreviousSubMenu();
287	        const previouslySelectedItem = previousMenuItems[enteredSubMenuIndexes[enteredSubMenuIndexes.length - 1]];
288	        const hasBackButtonText = !!previouslySelectedItem?.backButtonText;
289	
290	        return (
291	            <MenuItem
292	                key={previouslySelectedItem?.text}
293	                icon={Expensicons.BackArrow}
294	                iconFill={(isHovered) => (isHovered ? theme.iconHovered : theme.icon)}
295	                style={hasBackButtonText ? styles.pv0 : undefined}
296	                additionalIconStyles={[{width: variables.iconSizeSmall, height: variables.iconSizeSmall}, styles.opacitySemiTransparent, styles.mr1]}
297	                title={hasBackButtonText ? previouslySelectedItem?.backButtonText : previouslySelectedItem?.text}
298	                titleStyle={hasBackButtonText ? styles.createMenuHeaderText : undefined}
299	                shouldShowBasicTitle={hasBackButtonText}
300	                shouldCheckActionAllowedOnPress={false}
301	                description={previouslySelectedItem?.description}
302	                onPress={() => {
303	                    setCurrentMenuItems(previousMenuItems);
304	                    setFocusedIndex(-1);
305	                    setEnteredSubMenuIndexes((prevState) => prevState.slice(0, -1));
306	                }}
307	            />
308	        );
309	    };
310	
311	    const renderedMenuItems = currentMenuItems.map((item, menuIndex) => {
312	        const {text, onSelected, subMenuItems, shouldCallAfterModalHide, key, testID: menuItemTestID, shouldShowLoadingSpinnerIcon, ...menuItemProps} = item;
313	
314	        return (
315	            <OfflineWithFeedback
316	                // eslint-disable-next-line react/no-array-index-key
317	                key={key ?? `${item.text}_${menuIndex}`}
318	                pendingAction={item.pendingAction}
319	            >
320	                <FocusableMenuItem
321	                    // eslint-disable-next-line react/no-array-index-key
322	                    key={key ?? `${item.text}_${menuIndex}`}
323	                    pressableTestID={menuItemTestID ?? `PopoverMenuItem-${item.text}`}
324	                    title={text}
325	                    onPress={(event) => selectItem(menuIndex, event)}
326	                    focused={focusedIndex === menuIndex}
327	                    shouldShowSelectedItemCheck={shouldShowSelectedItemCheck}
328	                    shouldCheckActionAllowedOnPress={false}
329	                    iconRight={item.rightIcon}
330	                    shouldShowRightIcon={!!item.rightIcon}
331	                    onFocus={() => {
332	                        if (!shouldUpdateFocusedIndex) {
333	                            return;
334	                        }
335	                        setFocusedIndex(menuIndex);
336	                    }}
337	                    wrapperStyle={[
338	                        StyleUtils.getItemBackgroundColorStyle(!!item.isSelected, focusedIndex === menuIndex, item.disabled ?? false, theme.activeComponentBG, theme.hoverComponentBG),
339	                        shouldUseScrollView && !shouldUseModalPaddingStyle && StyleUtils.getOptionMargin(menuIndex, currentMenuItems.length - 1),
340	                    ]}
341	                    shouldRemoveHoverBackground={item.isSelected}
342	                    titleStyle={StyleSheet.flatten([styles.flex1, item.titleStyle])}
343	                    // Spread other props dynamically
344	                    {...menuItemProps}
345	                    hasSubMenuItems={!!subMenuItems?.length}
346	                    shouldShowLoadingSpinnerIcon={shouldShowLoadingSpinnerIcon}
347	                />
348	            </OfflineWithFeedback>
349	        );
350	    });
351	
352	    const renderHeaderText = () => {
353	        if (!headerText || enteredSubMenuIndexes.length !== 0) {
354	            return;
355	        }
356	        return <Text style={[styles.createMenuHeaderText, styles.ph5, styles.pv3, headerStyles]}>{headerText}</Text>;
357	    };
358	
359	    useKeyboardShortcut(
360	        CONST.KEYBOARD_SHORTCUTS.ENTER,
361	        () => {
362	            if (focusedIndex === -1) {
363	                return;
364	            }
365	            selectItem(focusedIndex);
366	            setFocusedIndex(-1); // Reset the focusedIndex on selecting any menu
367	        },
368	        {isActive: isVisible},
369	    );
370	
371	    const keyboardShortcutSpaceCallback = useCallback(
372	        (e?: GestureResponderEvent | KeyboardEvent) => {
373	            if (shouldUseScrollView) {
374	                return;
375	            }
376	
377	            e?.preventDefault();
378	        },
379	        [shouldUseScrollView],
380	    );
381	
382	    // On web and desktop, pressing the space bar after interacting with the parent view
383	    // can cause the parent view to scroll when the space bar is pressed.
384	    useKeyboardShortcut(CONST.KEYBOARD_SHORTCUTS.SPACE, keyboardShortcutSpaceCallback, {isActive: isWebOrDesktop && isVisible, shouldPreventDefault: false});
385	
386	    const handleModalHide = () => {
387	        onModalHide?.();
388	        setFocusedIndex(currentMenuItemsFocusedIndex);
389	    };
390	
391	    // When the menu items are changed, we want to reset the sub-menu to make sure
392	    // we are not accessing the wrong sub-menu parent or possibly undefined when rendering the back button.
393	    // We use useLayoutEffect so the reset happens before the repaint
394	    useLayoutEffect(() => {
395	        if (menuItems.length === 0) {
396	            return;
397	        }
398	        setEnteredSubMenuIndexes(CONST.EMPTY_ARRAY);
399	        setCurrentMenuItems(menuItems);
400	
401	        // Update the focused item to match the selected item, but only when the popover is not visible.
402	        // This ensures that if the popover is visible, highlight from the keyboard navigation is not overridden
403	        // by external updates.
404	        if (isVisible) {
405	            return;
406	        }
407	        setFocusedIndex(getSelectedItemIndex(menuItems));
408	
409	        // eslint-disable-next-line react-compiler/react-compiler, react-hooks/exhaustive-deps
410	    }, [menuItems, setFocusedIndex]);
411	
412	    const menuContainerStyle = useMemo(() => {
413	        if (isSmallScreenWidth) {
414	            return shouldEnableMaxHeight ? {maxHeight: windowHeight - 250} : {};
415	        }
416	        return styles.createMenuContainer;
417	    }, [isSmallScreenWidth, shouldEnableMaxHeight, windowHeight, styles.createMenuContainer]);
418	
419	    const {paddingTop, paddingBottom, paddingVertical, ...restScrollContainerStyle} = (StyleSheet.flatten([styles.pv4, scrollContainerStyle]) as ViewStyle) ?? {};
420	
421	    return (
422	        <PopoverWithMeasuredContent
423	            anchorPosition={anchorPosition}
424	            anchorRef={anchorRef}
425	            anchorAlignment={anchorAlignment}
426	            onClose={() => {
427	                setCurrentMenuItems(menuItems);
428	                setEnteredSubMenuIndexes(CONST.EMPTY_ARRAY);
429	                onClose();
430	            }}
431	            isVisible={isVisible}
432	            onModalHide={handleModalHide}
433	            onModalShow={onModalShow}
434	            animationIn={animationIn}
435	            animationOut={animationOut}
436	            animationInDelay={animationInDelay}
437	            animationInTiming={animationInTiming}
438	            animationOutTiming={animationOutTiming}
439	            disableAnimation={disableAnimation}
440	            fromSidebarMediumScreen={fromSidebarMediumScreen}
441	            withoutOverlay={withoutOverlay}
442	            shouldSetModalVisibility={shouldSetModalVisibility}
443	            shouldEnableNewFocusManagement={shouldEnableNewFocusManagement}
444	            useNativeDriver
445	            restoreFocusType={restoreFocusType}
446	            innerContainerStyle={{...styles.pv0, ...innerContainerStyle}}
447	            shouldUseModalPaddingStyle={shouldUseModalPaddingStyle}
448	            testID={testID}
449	        >
450	            <FocusTrapForModal active={isVisible}>
451	                <View
452	                    onLayout={onLayout}
453	                    style={[menuContainerStyle, containerStyles, {paddingTop, paddingBottom, paddingVertical, ...(isWebOrDesktop ? styles.flex1 : styles.flexGrow1)}]}
454	                >
455	                    {renderHeaderText()}
456	                    {enteredSubMenuIndexes.length > 0 && renderBackButtonItem()}
457	                    {renderWithConditionalWrapper(shouldUseScrollView, restScrollContainerStyle, renderedMenuItems)}
458	                </View>
459	            </FocusTrapForModal>
460	        </PopoverWithMeasuredContent>
461	    );
462	}
463	
464	PopoverMenu.displayName = 'PopoverMenu';
465	
466	export default React.memo(
467	    PopoverMenu,
468	    (prevProps, nextProps) =>
469	        deepEqual(prevProps.menuItems, nextProps.menuItems) &&
470	        prevProps.isVisible === nextProps.isVisible &&
471	        deepEqual(prevProps.anchorPosition, nextProps.anchorPosition) &&
472	        prevProps.anchorRef === nextProps.anchorRef &&
473	        prevProps.headerText === nextProps.headerText &&
474	        prevProps.fromSidebarMediumScreen === nextProps.fromSidebarMediumScreen &&
475	        deepEqual(prevProps.anchorAlignment, nextProps.anchorAlignment) &&
476	        prevProps.animationIn === nextProps.animationIn &&
477	        prevProps.animationOut === nextProps.animationOut &&
478	        prevProps.animationInTiming === nextProps.animationInTiming &&
479	        prevProps.disableAnimation === nextProps.disableAnimation &&
480	        prevProps.withoutOverlay === nextProps.withoutOverlay &&
481	        prevProps.shouldSetModalVisibility === nextProps.shouldSetModalVisibility,
482	);
483	export type {PopoverMenuItem, PopoverMenuProps};
